class Solution {
    public int[] shortestAlternatingPaths(int n, int[][] redEdges, int[][] blueEdges) {
        int[] answer = new int[n];
        Arrays.fill(answer, -1);
        Queue<int[]> redQueue = new LinkedList<>();
        Queue<int[]> blueQueue = new LinkedList<>();
        redQueue.offer(new int[]{0, 0});
        blueQueue.offer(new int[]{0, 1});
        while (!redQueue.isEmpty() || !blueQueue.isEmpty()) {
            if (!redQueue.isEmpty()) {
                int[] curr = redQueue.poll();
                int node = curr[0];
                int dist = curr[1];
                for (int[] edge : redEdges) {
                    if (edge[0] == node) {
                        int nextNode = edge[1];
                        if (answer[nextNode] == -1) {
                            answer[nextNode] = dist + 1;
                            redQueue.offer(new int[]{nextNode, dist + 1});
                        }
                    }
                }
            }
            if (!blueQueue.isEmpty()) {
                int[] curr = blueQueue.poll();
                int node = curr[0];
                int dist = curr[1];
                for (int[] edge : blueEdges) {
                    if (edge[0] == node) {
                        int nextNode = edge[1];
                        if (answer[nextNode] == -1) {
                            answer[nextNode] = dist + 1;
                            blueQueue.offer(new int[]{nextNode, dist + 1});
                        }
                    }
                }
            }
        }
        return answer;
    }
}
